def get_user(user_id):
    with sqlite3.connect('users.db') as conn:
        cursor = conn.cursor()
        try:
            return cursor.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        except sqlite3.Error as e:
            # Handle logging or re-raising here
